class Solution:
    def removeSubfolders(self, folder: List[str]) -> List[str]:
        folder.sort()
        res = []
        for f in folder:
            keep = True
            for i in range(2, len(f)):
                if f[i] == '/' and f[:i] in res:
                    keep = False
                    break
            if keep:
                res.append(f)
        return res
